config.script:
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function pageText(){var t=(document.title||'').toLowerCase();var b=(document.body?document.body.innerText:'')||'';return t+' '+b.toLowerCase();}
function networkErr(){var s=pageText();return s.includes("this site can't be reached")||s.includes("this site can’t be reached")||s.includes('err_connection')||s.includes('err_tunnel')||s.includes('err_proxy')||s.includes('err_timed_out')||s.includes('dns_probe_finished')||s.includes('check if there is a typo');}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function emailReady(){var sels=['input[name="Email"]','#input-54','input[type="email"]','form input'];for(var i=0;i<sels.length;i++){var el=document.querySelector(sels[i]);if(vis(el))return true;}return false;}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<45000){await sleep(200);}
var deadline=Date.now()+25000;
while(Date.now()<deadline){
  if(networkErr()) throw new Error('OASIS unreachable (proxy/network) - rotate proxy.');
  if(emailReady()) return (document.title||'').trim();
  await sleep(500);
}
if(networkErr()) throw new Error('OASIS unreachable (proxy/network) - rotate proxy.');
throw new Error('OASIS signup page did not load an email field in time.');

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
var deadline=Date.now()+8000;
var ripple=null;
while(Date.now()<deadline){
  ripple=Array.from(document.querySelectorAll('.v-input--selection-controls__ripple')).find(vis);
  if(ripple)break;
  await sleep(250);
}
if(!ripple)return 'no-agree-checkbox';
ripple.scrollIntoView({block:'center'});
ripple.click();
await sleep(300);
return 'agree-clicked';

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function firstNameField(){
  var sels=['input[placeholder="First name" i]','input[aria-label="First name" i]','input[name="firstName" i]','#input-73','#input-77'];
  for(var i=0;i<sels.length;i++){if(vis(document.querySelector(sels[i])))return true;}
  return false;
}
function registered(){
  var notYou=Array.from(document.querySelectorAll('.landingpage-header__email-accent b, .mr-1 b')).find(vis);
  if(notYou&&/not you/i.test(String(notYou.textContent||'')))return true;
  var body=String(document.body?document.body.innerText:'').toLowerCase();
  if(vis(document.querySelector('.footer-link'))&&/(log in|sign in|already have)/i.test(body))return true;
  return false;
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<20000){await sleep(200);}
var deadline=Date.now()+30000;
while(Date.now()<deadline){
  if(firstNameField())return 'signup';
  if(registered()) throw new Error('OASIS account already exists for this email - marking email as used.');
  await sleep(300);
}
if(registered()) throw new Error('OASIS account already exists for this email - marking email as used.');
throw new Error('Email step did not resolve to the signup details form.');

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
var deadline=Date.now()+15000;
var items=[];
while(Date.now()<deadline){
  items=Array.from(document.querySelectorAll('.v-list-item__title')).filter(vis);
  if(items.length)break;
  await sleep(250);
}
if(!items.length) throw new Error('OASIS address suggestions did not appear.');
var first=items[0];
if(/we couldn't find that town|we couldn’t find that town|no results|not found/i.test(String(first.textContent||''))){
  throw new Error('OASIS did not recognize the address - retry with a new address.');
}
var clickable=(first.closest&&first.closest('.v-list-item'))||first;
clickable.scrollIntoView({block:'center'});
clickable.click();
await sleep(400);
return String(first.textContent||'').trim();

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
async function waitFor(fn,ms){var d=Date.now()+ms;while(Date.now()<d){var v=fn();if(v)return v;await sleep(200);}return null;}
var age=18+Math.floor(Math.random()*38);
var year=(new Date()).getFullYear()-age;
var yearLi=await waitFor(function(){
  var lis=Array.from(document.querySelectorAll('.v-date-picker-years li, .v-picker__body ul li'));
  return lis.find(function(el){return vis(el)&&String(el.textContent||'').trim()===String(year);});
},15000);
if(!yearLi){
  var anyLis=Array.from(document.querySelectorAll('.v-date-picker-years li, .v-picker__body ul li')).filter(vis);
  if(!anyLis.length) throw new Error('DOB year list not found.');
  yearLi=anyLis[Math.floor(anyLis.length/2)];
  year=parseInt(String(yearLi.textContent||'').trim(),10)||year;
}
yearLi.scrollIntoView({block:'center'});
yearLi.click();
await sleep(800);
var monthBtns=await waitFor(function(){
  var b=Array.from(document.querySelectorAll('.v-date-picker-table--month button, .v-date-picker-table--month .v-btn')).filter(function(el){return vis(el)&&!el.disabled;});
  return b.length?b:null;
},10000);
if(!monthBtns) throw new Error('DOB month picker not found.');
var mi=Math.floor(Math.random()*monthBtns.length);
monthBtns[mi].scrollIntoView({block:'center'});
monthBtns[mi].click();
await sleep(800);
var dayBtns=await waitFor(function(){
  var b=Array.from(document.querySelectorAll('.v-date-picker-table--date button, .v-date-picker-table--date .v-btn')).filter(function(el){return vis(el)&&!el.disabled&&String(el.textContent||'').trim();});
  return b.length?b:null;
},10000);
if(!dayBtns) throw new Error('DOB day picker not found.');
var di=Math.floor(Math.random()*dayBtns.length);
var dayText=String(dayBtns[di].textContent||'').trim();
dayBtns[di].scrollIntoView({block:'center'});
dayBtns[di].click();
await sleep(500);
return year+'-'+(mi+1)+'-'+dayText;

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
var deadline=Date.now()+10000;
var ripples=[];
while(Date.now()<deadline){
  ripples=Array.from(document.querySelectorAll('.v-input--selection-controls__ripple')).filter(vis);
  if(ripples.length)break;
  await sleep(250);
}
if(!ripples.length) throw new Error('OASIS terms checkbox not found.');
var target=ripples[ripples.length-1];
target.scrollIntoView({block:'center'});
target.click();
await sleep(300);
return 'terms-checked';

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function snap(){var t=(document.title||'').toLowerCase();var b=String(document.body?document.body.innerText:'').toLowerCase();return {b:b,all:t+' '+b};}
function formStillUp(){
  var sels=['input[placeholder="First name" i]','input[type="tel"]','input[autocomplete="no-thanks"]'];
  for(var i=0;i<sels.length;i++){if(vis(document.querySelector(sels[i])))return true;}
  return false;
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<30000){await sleep(200);}
var deadline=Date.now()+30000;
while(Date.now()<deadline){
  var s=snap();
  if(s.all.includes("this site can't be reached")||s.all.includes('err_connection')||s.all.includes('err_proxy')||s.all.includes('err_timed_out')) throw new Error('OASIS submission unreachable - rotate proxy.');
  if(/welcome|check your email|verify your email|confirm your email|thank you|account created|you're all set|success/i.test(s.b) && !formStillUp())return 'done';
  if(!formStillUp() && !/signupwb/i.test(location.href))return 'done';
  await sleep(400);
}
if(formStillUp()) throw new Error('OASIS signup did not complete (form still present - check for validation errors).');
return 'done';
